// 生成更多随机点数据的工具函数
export function generateRandomPoints(count = 50, centerLat = 39.90923, centerLng = 116.397428, radius = 0.05) {
  const points = [];
  for (let i = 0; i < count; i++) {
    // 生成随机经纬度 (在中心点附近)
    const lat = centerLat + (Math.random() - 0.5) * 2 * radius;
    const lng = centerLng + (Math.random() - 0.5) * 2 * radius;
    
    points.push({
      id: i + 11, // 避免与上面的固定ID冲突
      latitude: lat,
      longitude: lng,
      title: `随机点 ${i + 1}`,
      count: 1,
      iconPath: "/static/markers/normal_marker.png",
      width: 30,
      height: 30
    });
  }
  return points;
}